#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        long long *a = (long long*)malloc(sizeof(long long) * N);
        long long *b = (long long*)malloc(sizeof(long long) * N);
        for (int i = 0; i < N; ++i) {
            scanf("%lld/%lld", &a[i], &b[i]);
        }
        for (int i = 0; i < N; ++i) {
            long long bestNum = a[i];
            long long bestDen = b[i];
            long long curNum = 0;
            long long curDen = 0;
            for (int j = i; j < N; ++j) {
                curNum += a[j];
                curDen += b[j];
                if (curNum * bestDen > bestNum * curDen) {
                    bestNum = curNum;
                    bestDen = curDen;
                }
            }
            printf("%lld/%lld\n", bestNum, bestDen);
        }
        free(a);
        free(b);
    }
    return 0;
}

