code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            long[] a = new long[N];
            long[] b = new long[N];
            for (int i = 0; i < N; i++) {
                String line = br.readLine().trim();
                int slash = line.indexOf('/');
                a[i] = Long.parseLong(line.substring(0, slash));
                b[i] = Long.parseLong(line.substring(slash + 1));
            }
            for (int i = 0; i < N; i++) {
                long bestNum = a[i];
                long bestDen = b[i];
                long curNum = 0;
                long curDen = 0;
                for (int j = i; j < N; j++) {
                    curNum += a[j];
                    curDen += b[j];
                    if (curNum * bestDen > bestNum * curDen) {
                        bestNum = curNum;
                        bestDen = curDen;
                    }
                }
                out.append(bestNum).append('/').append(bestDen).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

