const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(lines[idx++]);
  const a = [];
  const b = [];
  for (let i = 0; i < N; i++) {
    const [num, den] = lines[idx++].split('/').map(Number);
    a.push(num);
    b.push(den);
  }
  for (let i = 0; i < N; i++) {
    let bestNum = a[i];
    let bestDen = b[i];
    let curNum = 0;
    let curDen = 0;
    for (let j = i; j < N; j++) {
      curNum += a[j];
      curDen += b[j];
      if (curNum * bestDen > bestNum * curDen) {
        bestNum = curNum;
        bestDen = curDen;
      }
    }
    output.push(`${bestNum}/${bestDen}`);
  }
}
